+"use client";
+
+import { useState, useRef, useEffect } from 'react';
+import { usePathname } from 'next/navigation';
+import { useTheme } from 'next-themes';
+import {
+  CURRENT_VERSION,
+  getAllVersions,
+  getVersionUrl,
+  type VersionKey,
+} from '@/config/versions';
+
+interface VersionSelectorProps {
+  className?: string;
+  isMobile?: boolean;
+}
+
+export function VersionSelector({ className = '', isMobile = false }: VersionSelectorProps) {
+  const [isOpen, setIsOpen] = useState(false);
+  const dropdownRef = useRef<HTMLDivElement>(null);
+  const pathname = usePathname();
+  const { resolvedTheme } = useTheme();
+  const isDark = resolvedTheme === 'dark';
+
+  // Get all versions
+  const versions = getAllVersions();
+
+  // Current version label (from the default/latest version)
+  const currentVersionLabel = `v${CURRENT_VERSION}`;
+
+  // Close dropdown when clicking outside
+  useEffect(() => {
+    function handleClickOutside(event: MouseEvent) {
+      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
+        setIsOpen(false);
+      }
+    }
+
+    document.addEventListener('mousedown', handleClickOutside);
+    return () => document.removeEventListener('mousedown', handleClickOutside);
+  }, []);
+
+  // Close dropdown on escape key
+  useEffect(() => {
+    function handleEscape(event: KeyboardEvent) {
+      if (event.key === 'Escape') {
+        setIsOpen(false);
+      }
+    }
+
+    document.addEventListener('keydown', handleEscape);
+    return () => document.removeEventListener('keydown', handleEscape);
+  }, []);
+
+  const handleVersionChange = (versionKey: VersionKey) => {
+    setIsOpen(false);
+
+    // Get the URL for the selected version
+    const url = getVersionUrl(versionKey, pathname);
+
+    // Navigate to the new version
+    window.location.href = url;
+  };
+
+  if (isMobile) {
+    // Mobile version - expandable list
+    return (
+      <div className={className}>
+        <button
+          onClick={() => setIsOpen(!isOpen)}
+          className={`flex items-center justify-between w-full px-3 py-2 text-sm rounded-md transition-colors ${
+            isDark
+              ? 'text-gray-300 hover:bg-neutral-800'
+              : 'text-gray-700 hover:bg-gray-100'
+          }`}
+        >
+          <span className="flex items-center">
+            <svg className="w-4 h-4 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
+              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 7h.01M7 3h5c.512 0 1.024.195 1.414.586l7 7a2 2 0 010 2.828l-7 7a2 2 0 01-2.828 0l-7-7A1.994 1.994 0 013 12V7a4 4 0 014-4z" />
+            </svg>
+            Version: {currentVersionLabel}
+          </span>
+          <svg
+            className={`w-4 h-4 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}
+            fill="none"
+            stroke="currentColor"
+            viewBox="0 0 24 24"
+          >
+            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
+          </svg>
+        </button>
+
+        {isOpen && (
+          <div className="mt-1 ml-7 space-y-1">
+            {versions.map(({ key, label }) => {
+              const isCurrentVersion = key === 'latest';
+              return (
+                <button
+                  key={key}
+                  onClick={() => handleVersionChange(key)}
+                  className={`block w-full text-left px-3 py-2 text-sm rounded-md transition-colors ${
+                    isCurrentVersion
+                      ? isDark
+                        ? 'bg-neutral-800 text-white font-medium'
+                        : 'bg-gray-100 text-gray-900 font-medium'
+                      : isDark
+                        ? 'text-gray-400 hover:bg-neutral-800 hover:text-gray-200'
+                        : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
+                  }`}
+                >
+                  {label}
+                  {key === 'legacy' && (
+                    <svg className="w-3 h-3 ml-1 inline-block" fill="none" stroke="currentColor" viewBox="0 0 24 24">
+                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
+                    </svg>
+                  )}
+                </button>
+              );
+            })}
+          </div>
+        )}
+      </div>
+    );
+  }
+
+  // Desktop version - dropdown
+  return (
+    <div className={`relative ${className}`} ref={dropdownRef}>
+      <button
+        onClick={() => setIsOpen(!isOpen)}
+        className={`flex items-center gap-1 text-xs font-mono px-2 py-1.5 rounded-md transition-colors cursor-pointer ${
+          isDark
+            ? 'text-gray-400 bg-neutral-800/50 hover:bg-neutral-700 hover:text-gray-200'
+            : 'text-gray-600 bg-gray-100 hover:bg-gray-200 hover:text-gray-900'
+        }`}
+        aria-haspopup="listbox"
+        aria-expanded={isOpen}
+        aria-label="Select documentation version"
+      >
+        <span>{currentVersionLabel}</span>
+        <svg
+          className={`w-3 h-3 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}
+          fill="none"
+          stroke="currentColor"
+          viewBox="0 0 24 24"
+        >
+          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
+        </svg>
+      </button>
+
+      {isOpen && (
+        <div
+          className={`absolute top-full right-0 mt-1 w-44 max-h-80 overflow-y-auto rounded-md shadow-lg border z-50 ${
+            isDark
+              ? 'bg-neutral-900 border-neutral-700'
+              : 'bg-white border-gray-200'
+          }`}
+          role="listbox"
+          aria-label="Documentation versions"
+        >
+          <div className="py-1">
+            {versions.map(({ key, label }) => {
+              const isCurrentVersion = key === 'latest';
+              const isExternal = key === 'legacy';
+
+              return (
+                <button
+                  key={key}
+                  onClick={() => handleVersionChange(key)}
+                  className={`flex items-center justify-between w-full text-left px-3 py-2 text-sm transition-colors ${
+                    isCurrentVersion
+                      ? isDark
+                        ? 'bg-neutral-800 text-white font-medium'
+                        : 'bg-gray-100 text-gray-900 font-medium'
+                      : isDark
+                        ? 'text-gray-300 hover:bg-neutral-800'
+                        : 'text-gray-700 hover:bg-gray-50'
+                  }`}
+                  role="option"
+                  aria-selected={isCurrentVersion}
+                >
+                  <span>{label}</span>
+                  {isExternal && (
+                    <svg className="w-3 h-3 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
+                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
+                    </svg>
+                  )}
+                </button>
+              );
+            })}
+          </div>
+        </div>
+      )}
+    </div>
+  );
+}
+
+export default VersionSelector;

